import{_ as t,o as r,c as a,ag as s}from"./chunks/framework.6ZJjlmu_.js";const b=JSON.parse('{"title":"Time travel and subscribers","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/time-travel-and-subscribers.md","filePath":"concepts/time-travel-and-subscribers.md"}'),o={name:"concepts/time-travel-and-subscribers.md"};function n(i,e,l,d,h,c){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="time-travel-and-subscribers" tabindex="-1">Time travel and subscribers <a class="header-anchor" href="#time-travel-and-subscribers" aria-label="Permalink to &quot;Time travel and subscribers&quot;">‚Äã</a></h1><h2 id="what-time-travel-does" tabindex="-1">What time travel does <a class="header-anchor" href="#what-time-travel-does" aria-label="Permalink to &quot;What time travel does&quot;">‚Äã</a></h2><p>In the <strong>Log</strong> tab, after you <strong>select a row</strong>, you can enable <strong>Time Travel</strong> and move the slider. Event Monitor <strong>replays SUB and UNSUB records only</strong> from the start of the session up to the chosen index and rebuilds the <strong>subscriber graph</strong> shown on the <strong>Subscribers</strong> tab.</p><p>So at any scrub position you can ask: <em>‚ÄúWho was subscribed to each event at this point in the timeline?‚Äù</em></p><h2 id="what-time-travel-does-not-do" tabindex="-1">What time travel does not do <a class="header-anchor" href="#what-time-travel-does-not-do" aria-label="Permalink to &quot;What time travel does not do&quot;">‚Äã</a></h2><ul><li>The <strong>log list</strong> does not rewind ‚Äî you are not viewing history-only UI; you are choosing a <strong>cut point</strong> for subscriber state.</li><li><strong>INVOKE</strong> rows do not change the replayed graph (invocations do not add or remove listeners in this model).</li></ul><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">‚Äã</a></h2><ol><li>Open <strong>Log</strong>, find an interesting <strong>INVOKE</strong> or <strong>SUB</strong> row.</li><li>Select it, enable <strong>Time Travel</strong>, scrub if needed.</li><li>Open <strong>Subscribers</strong> ‚Äî the graph matches replayed state at the scrub index.</li></ol><h2 id="live-vs-replayed" tabindex="-1">Live vs replayed <a class="header-anchor" href="#live-vs-replayed" aria-label="Permalink to &quot;Live vs replayed&quot;">‚Äã</a></h2><p>With time travel <strong>off</strong>, <strong>Subscribers</strong> shows <strong>live</strong> state (current handlers). With time travel <strong>on</strong>, it shows <strong>replayed</strong> state at the slider position.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">‚Äã</a></h2><ul><li><a href="./event-bus-and-records.html">Event bus and records</a></li><li><a href="./../guide/quick-start.html">Quick Start</a></li></ul>',12)])])}const g=t(o,[["render",n]]);export{b as __pageData,g as default};
